<?php
namespace App\Domain\Shops\Admin;
use App\Domain\Media\MediaAssetService;use App\Domain\Media\MediaAssetType;use App\Models\MediaAsset;use Illuminate\Database\Eloquent\Model;use Illuminate\Http\UploadedFile;use Illuminate\Support\Facades\DB;use Illuminate\Support\Facades\Storage;use Illuminate\Support\Str;use InvalidArgumentException;use Throwable;
final class ShopMediaService{const DISK='public';const MAX_BYTES=5242880;private $media;public function __construct(MediaAssetService $media){$this->media=$media;}public function persist($modelCallback,array $changes){$stored=[];$previous=[];foreach($changes as$type=>$change){if($change['file']&&$change['remove'])throw new InvalidArgumentException('No se puede reemplazar y eliminar la misma imagen.');if($change['file'])$stored[$type]=$this->store($type,$change['file']);}try{$model=DB::transaction(function()use($modelCallback,$changes,$stored,&$previous){$model=$modelCallback();if(!$model instanceof Model||!$model->exists)throw new InvalidArgumentException('Invalid Shop media owner.');foreach($changes as$type=>$change){if(isset($stored[$type])){$result=$this->media->replacePrimary($model,array_merge($stored[$type],['asset_type'=>$type,'is_primary'=>true]));if($result['previous'])$previous[]=$result['previous'];}elseif($change['remove']){$old=$this->media->deletePrimary($model,$type);if($old)$previous[]=$old;}}return$model;},3);}catch(Throwable $e){foreach($stored as$data)$this->delete($data['disk'],$data['path']);throw$e;}foreach($previous as$asset)$this->delete($asset->disk,$asset->path);return$model;}public function presentation(Model $model,$type){$asset=$model->relationLoaded('mediaAssets')?$model->mediaAssets->filter(function($a)use($type){return$a->asset_type===$type&&$a->is_primary;})->sortBy('id')->first():null;if(!$asset)return['exists'=>false,'url'=>null,'name'=>null,'width'=>null,'height'=>null,'size_label'=>null,'format'=>null];$meta=is_array($asset->metadata)?$asset->metadata:[];return['exists'=>true,'url'=>$asset->url(),'name'=>isset($meta['original_name'])?$meta['original_name']:basename($asset->path),'width'=>(int)$asset->width,'height'=>(int)$asset->height,'size_label'=>$this->size((int)$asset->file_size),'format'=>$this->format($asset->mime_type)];}private function store($type,UploadedFile $file){$info=$this->inspect($file);$owner=$type===MediaAssetType::PORTRAIT?'npcs':'shops';$path='game-assets/'.$owner.'/'.date('Y/m').'/'.(string)Str::uuid().'/'.$type.'.'.$info['extension'];$stream=fopen($file->getRealPath(),'rb');try{if($stream===false||!Storage::disk(self::DISK)->put($path,$stream))throw new InvalidArgumentException('No se pudo almacenar la imagen.');}finally{if(is_resource($stream))fclose($stream);}return['disk'=>self::DISK,'path'=>$path,'mime_type'=>$info['mime'],'width'=>$info['width'],'height'=>$info['height'],'file_size'=>$info['size'],'metadata'=>['shop_media_version'=>1,'original_name'=>$file->getClientOriginalName()],'sort_order'=>0];}private function inspect(UploadedFile $file){$path=$file->getRealPath();$size=$file->getSize();if(!$file->isValid()||!is_file($path)||$size<=0||$size>self::MAX_BYTES)throw new InvalidArgumentException('La imagen no es válida o supera 5 MB.');$mime=(new \finfo(FILEINFO_MIME_TYPE))->file($path);$image=@getimagesize($path);$allowed=['image/png'=>'png','image/jpeg'=>'jpg','image/webp'=>'webp'];if(!$image||!isset($allowed[$mime])||$image['mime']!==$mime)throw new InvalidArgumentException('Solo se permiten PNG, JPG o WebP válidos.');$decoder=['image/png'=>'imagecreatefrompng','image/jpeg'=>'imagecreatefromjpeg','image/webp'=>'imagecreatefromwebp'];$resource=@call_user_func($decoder[$mime],$path);if(!$resource)throw new InvalidArgumentException('La imagen está corrupta.');imagedestroy($resource);return['mime'=>$mime,'extension'=>$allowed[$mime],'width'=>(int)$image[0],'height'=>(int)$image[1],'size'=>(int)$size];}private function delete($disk,$path){try{Storage::disk($disk)->delete($path);}catch(Throwable $e){}}private function size($bytes){return$bytes>=1048576?round($bytes/1048576,2).' MB':max(1,(int)ceil($bytes/1024)).' KB';}private function format($mime){return$mime==='image/jpeg'?'JPG':strtoupper(substr((string)$mime,strpos((string)$mime,'/')+1));}}
